const STORAGE_KEY = 'notepad-content';
const ON_AUTOSAVE_TRIGGERED = 'OnAutosaveTriggered';

let intervalId;
let dotNetRef;
let isDirty = false;

function onBeforeUnload(e) {
    if (isDirty) {
        e.preventDefault();
    }
}

export function initialize(dotNetReference, intervalMs) {
    dotNetRef = dotNetReference;

    window.addEventListener('beforeunload', onBeforeUnload);

    intervalId = setInterval(async () => {
        try {
            await dotNetRef.invokeMethodAsync(ON_AUTOSAVE_TRIGGERED);
        } catch { /* circuit disconnected */ }
    }, intervalMs);
}

export function save(content) {
    localStorage.setItem(STORAGE_KEY, content);
    isDirty = false;
}

export function load() {
    return localStorage.getItem(STORAGE_KEY);
}

export function clear() {
    localStorage.removeItem(STORAGE_KEY);
    isDirty = false;
}

export function markDirty() {
    isDirty = true;
}

export function dispose() {
    clearInterval(intervalId);
    window.removeEventListener('beforeunload', onBeforeUnload);
}

using Microsoft.JSInterop;

namespace sv_2f7a11caf2a0467fba7db1aebf30e6a7.Components.Pages;

public sealed class NotepadInterop : IAsyncDisposable
{
    internal const string ModulePath = "./Components/Pages/Notepad.razor.js";
    internal const string InitializeMethod = "initialize";
    internal const string SaveMethod = "save";
    internal const string LoadMethod = "load";
    internal const string ClearMethod = "clear";
    internal const string MarkDirtyMethod = "markDirty";
    internal const string DisposeMethod = "dispose";

    private readonly IJSRuntime _js;
    private IJSObjectReference? _module;

    public NotepadInterop(IJSRuntime js) => _js = js;

    private async ValueTask<IJSObjectReference> GetModuleAsync()
        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);

    public async ValueTask InitializeAsync<T>(DotNetObjectReference<T> dotNetRef, int intervalMs) where T : class
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(InitializeMethod, dotNetRef, intervalMs);
    }

    public async ValueTask SaveAsync(string content)
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(SaveMethod, content);
    }

    public async ValueTask<string?> LoadAsync()
    {
        var module = await GetModuleAsync();
        return await module.InvokeAsync<string?>(LoadMethod);
    }

    public async ValueTask ClearAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(ClearMethod);
    }

    public async ValueTask MarkDirtyAsync()
    {
        var module = await GetModuleAsync();
        await module.InvokeVoidAsync(MarkDirtyMethod);
    }

    public async ValueTask DisposeAsync()
    {
        try
        {
            if (_module is not null)
            {
                await _module.InvokeVoidAsync(DisposeMethod);
                await _module.DisposeAsync();
            }
        }
        catch (JSDisconnectedException) { }
