+    private async ValueTask<IJSObjectReference> GetModuleAsync()
+        => _module ??= await _js.InvokeAsync<IJSObjectReference>("import", ModulePath);
+
+    public async ValueTask InitializeAsync<T>(DotNetObjectReference<T> dotNetRef, int intervalMs) where T : class
+    {
+        var module = await GetModuleAsync();
+        await module.InvokeVoidAsync(InitializeMethod, dotNetRef, intervalMs);
+    }
+
+    public async ValueTask SaveAsync(string content)
+    {
+        var module = await GetModuleAsync();
+        await module.InvokeVoidAsync(SaveMethod, content);
+    }
+
+    public async ValueTask<string?> LoadAsync()
+    {
+        var module = await GetModuleAsync();
+        return await module.InvokeAsync<string?>(LoadMethod);
+    }
+
+    public async ValueTask ClearAsync()
+    {
+        var module = await GetModuleAsync();
+        await module.InvokeVoidAsync(ClearMethod);
+    }
+
+    public async ValueTask MarkDirtyAsync()
+    {
+        var module = await GetModuleAsync();
+        await module.InvokeVoidAsync(MarkDirtyMethod);
+    }
+
+    public async ValueTask DisposeAsync()
+    {
+        try
+        {
+            if (_module is not null)
+            {
+                await _module.InvokeVoidAsync(DisposeMethod);
+                await _module.DisposeAsync();
+            }
+        }
+        catch (JSDisconnectedException) { }
+    }
+}
