@page "/notepad"
@rendermode InteractiveServer
@inject IJSRuntime JS
@implements IAsyncDisposable

<PageTitle>Notepad</PageTitle>

<h1>Notepad</h1>

<textarea @bind="_content" @bind:event="oninput" @bind:after="OnContentChangedAsync" rows="15" style="width:100%;"></textarea>

<div style="margin-top:0.5rem; display:flex; align-items:center; gap:1rem;">
    <button @onclick="SaveNowAsync">Save now</button>
    <button @onclick="ClearAsync">Clear</button>
    @if (_lastSaved is not null)
    {
        <span>Last saved at @_lastSaved.Value.ToString("HH:mm:ss")</span>
    }
</div>

@code {
    private const int AutosaveIntervalMs = 30_000;

    private string _content = string.Empty;
    private DateTime? _lastSaved;
    private string? _savedSnapshot;
    private NotepadInterop? _interop;
    private DotNetObjectReference<Notepad>? _dotNetRef;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            _interop = new NotepadInterop(JS);
            var restored = await _interop.LoadAsync();
            if (restored is not null)
            {
                _content = restored;
                _savedSnapshot = restored;
                StateHasChanged();
            }

            _dotNetRef = DotNetObjectReference.Create(this);
            await _interop.InitializeAsync(_dotNetRef, AutosaveIntervalMs);
        }
    }

    private bool HasUnsavedChanges => _content != _savedSnapshot;

    private async Task OnContentChangedAsync()
    {
        if (_interop is not null && HasUnsavedChanges)
        {
            await _interop.MarkDirtyAsync();
        }
    }

    [JSInvokable]
    public async Task OnAutosaveTriggered()
    {
        await InvokeAsync(async () =>
        {
            if (HasUnsavedChanges)
            {
                await SaveAsync();
                StateHasChanged();
            }
        });
    }

    private async Task SaveNowAsync()
    {
        if (_interop is not null)
        {
            await SaveAsync();
        }
    }

    private async Task SaveAsync()
    {
        if (_interop is not null)
        {
            await _interop.SaveAsync(_content);
            _savedSnapshot = _content;
            _lastSaved = DateTime.Now;
        }
    }

    private async Task ClearAsync()
    {
        if (_interop is not null)
        {
            await _interop.ClearAsync();
            _content = string.Empty;
            _savedSnapshot = string.Empty;
            _lastSaved = null;
        }
    }

    async ValueTask IAsyncDisposable.DisposeAsync()
    {
        if (_interop is not null)
            await _interop.DisposeAsync();

        _dotNetRef?.Dispose();
    }
}

